1	/**
2	 * The Fabricator — guild engine design registry apparatus.
3	 *
4	 * Scans installed engine designs from kit contributions and apparatus supportKits,
5	 * and serves them to the Spider on demand.
6	 *
7	 * The Fabricator does not execute engines. It is a pure query service:
8	 * designs in, designs out.
9	 */
10	
11	import type {
12	  StartupContext,
13	  Plugin,
14	} from '@shardworks/nexus-core';
15	
16	// ── Public types ──────────────────────────────────────────────────────
17	
18	/** Minimal execution context passed to an engine's run() method. */
19	export interface EngineRunContext {
20	  /** The rig this engine instance belongs to. */
21	  rigId: string;
22	  /** Simple string identity for this engine instance (e.g. 'draft', 'implement'). */
23	  engineId: string;
24	  /** All upstream yields, keyed by engine id. Escape hatch for engines that need to inspect the full upstream chain. */
25	  upstream: Record<string, unknown>;
26	  /**
27	   * Present when this engine was previously blocked and has been restarted.
28	   * Advisory — do not depend on for correctness.
29	   *
30	   * Note: Defined inline to avoid a circular package dependency with spider-apparatus.
31	   * Shape matches spider-apparatus BlockRecord exactly.
32	   */
33	  priorBlock?: {
34	    type: string;
35	    condition: unknown;
36	    blockedAt: string;
37	    message?: string;
38	    lastCheckedAt?: string;
39	  };
40	}
41	
42	/**
43	 * The result of an engine run.
44	 *
45	 * 'completed' — synchronous work done inline, yields are available immediately.
46	 * 'launched'  — async work launched in a session; the Spider polls for completion.
47	 * 'blocked'   — engine is waiting for an external condition; Spider will poll
48	 *               the registered block type's checker and restart when cleared.
49	 */
50	export type EngineRunResult =
51	  | { status: 'completed'; yields: unknown }
52	  | { status: 'launched'; sessionId: string }
53	  | { status: 'blocked'; blockType: string; condition: unknown; message?: string };
54	
55	/**
56	 * An engine design — the unit of work the Fabricator catalogues and the
57	 * Spider executes. Kit authors import this type from @shardworks/fabricator-apparatus.
58	 */
59	export interface EngineDesign {
60	  /** Unique identifier for this engine design (e.g. 'draft', 'implement', 'review'). */
61	  id: string;
62	
63	  /**
64	   * Execute this engine.
65	   *
66	   * @param givens   — the engine's declared inputs, assembled by the Spider.
67	   * @param context  — minimal execution context: engine id and upstream yields.
68	   */
69	  run(givens: Record<string, unknown>, context: EngineRunContext): Promise<EngineRunResult>;
70	
71	  /**
72	   * Assemble yields from a completed session.
73	   *
74	   * Called by the Spider's collect step when a quick engine's session
75	   * reaches a terminal state. The engine looks up whatever it needs
76	   * via guild() — same dependency pattern as run().
77	   *
78	   * @param sessionId — the session to collect yields from (primary input).
79	   * @param givens    — same givens that were passed to run().
80	   * @param context   — same execution context that was passed to run().
81	   *
82	   * If not defined, the Spider uses a generic default:
83	   *   { sessionId, sessionStatus, output? }
84	   *
85	   * Only relevant for quick engines (those that return { status: 'launched' }).
86	   * Clockwork engines return yields directly from run().
87	   */
88	  collect?(sessionId: string, givens: Record<string, unknown>, context: EngineRunContext): Promise<unknown>;
89	}
90	
91	/** Summary info for a registered engine design. */
92	export interface EngineDesignInfo {
93	  /** Engine design id. */
94	  id: string;
95	  /** Plugin id that contributed this design. */
96	  pluginId: string;
97	  /** Whether the design defines a collect() method (indicates quick engine with custom yield assembly). */
98	  hasCollect: boolean;
99	}
100	
101	/** The Fabricator's public API, exposed via `provides`. */
102	export interface FabricatorApi {
103	  /**
104	   * Look up an engine design by ID.
105	   * Returns the design if registered, undefined otherwise.
106	   */
107	  getEngineDesign(id: string): EngineDesign | undefined;
108	
109	  /**
110	   * List all registered engine designs with summary info.
111	   */
112	  listEngineDesigns(): EngineDesignInfo[];
113	}
114	
115	// ── Type guard ────────────────────────────────────────────────────────
116	
117	/** Narrow an unknown value to EngineDesign. */
118	function isEngineDesign(value: unknown): value is EngineDesign {
119	  return (
120	    typeof value === 'object' &&
121	    value !== null &&
122	    typeof (value as Record<string, unknown>).id === 'string' &&
123	    typeof (value as Record<string, unknown>).run === 'function'
124	  );
125	}
126	
127	// ── Implementation ────────────────────────────────────────────────────
128	
129	/** The engine design registry — populated at startup, queried at runtime. */
130	class EngineRegistry {
131	  private readonly designs = new Map<string, EngineDesign>();
132	  private readonly provenance = new Map<string, string>();
133	
134	  /** Extract and register engine designs from a kit (or supportKit) contribution. */
135	  registerFromKit(kit: Record<string, unknown>, pluginId: string): void {
136	    const rawEngines = kit.engines;
137	    if (typeof rawEngines !== 'object' || rawEngines === null) return;
138	
139	    for (const value of Object.values(rawEngines as Record<string, unknown>)) {
140	      if (isEngineDesign(value)) {
141	        this.designs.set(value.id, value);
142	        this.provenance.set(value.id, pluginId);
143	      }
144	    }
145	  }
146	
147	  /** Look up an engine design by ID. */
148	  get(id: string): EngineDesign | undefined {
149	    return this.designs.get(id);
150	  }
151	
152	  /** List all registered engine designs with summary info. */
153	  list(): EngineDesignInfo[] {
154	    const result: EngineDesignInfo[] = [];
155	    for (const [id, design] of this.designs) {
156	      result.push({
157	        id,
158	        pluginId: this.provenance.get(id) ?? 'unknown',
159	        hasCollect: typeof design.collect === 'function',
160	      });
161	    }
162	    return result;
163	  }
164	}
165	
166	// ── Apparatus factory ─────────────────────────────────────────────────
167	
168	/**
169	 * Create the Fabricator apparatus plugin.
170	 *
