904	// ── Apparatus factory ──────────────────────────────────────────────────
905	
906	export function createSpider(): Plugin {
907	  let rigsBook: Book<RigDoc>;
908	  let sessionsBook: ReadOnlyBook<SessionDoc>;
909	  let writsBook: ReadOnlyBook<WritDoc>;
910	  let clerk: ClerkApi;
911	  let fabricator: FabricatorApi;
912	  let spiderConfig: SpiderConfig = {};
913	
914	  const blockTypeRegistry = new BlockTypeRegistry();
915	  const rigTemplateRegistry = new RigTemplateRegistry();
916	
917	  /**
918	   * In-memory store for block records that have been cleared.
919	   * Key: "rigId:engineId". Written when an engine is unblocked (via checker or resume()).
920	   * Read and deleted in tryRun() when building EngineRunContext.
921	   */
922	  const pendingPriorBlocks = new Map<string, BlockRecord>();
923	
924	  // ── Internal crawl operations ─────────────────────────────────────
925	
926	  /**
927	   * Mark an engine failed and propagate failure to the rig (same update).
928	   * Cancels all pending and blocked engines.
929	   */
930	  async function failEngine(
931	    rig: RigDoc,
932	    engineId: string,
933	    errorMessage: string,
934	  ): Promise<void> {
935	    const now = new Date().toISOString();
936	    const updatedEngines = rig.engines.map((e) => {
937	      if (e.id === engineId) {
938	        return { ...e, status: 'failed' as const, error: errorMessage, completedAt: now };
939	      }
940	      if (e.status === 'pending' || e.status === 'blocked') {
941	        return { ...e, status: 'cancelled' as const, block: undefined };
942	      }
943	      return e;
944	    });
945	    await rigsBook.patch(rig.id, {
946	      engines: updatedEngines,
947	      status: 'failed',
948	    });
949	  }
950	
951	  /**
952	   * Phase 1 — collect.
953	   *
954	   * Find the first running engine with a sessionId whose session has
955	   * reached a terminal state. Populate yields and advance the engine
956	   * (and possibly the rig) to completed or failed.
957	   *
958	   * After collecting a completed engine, check whether the rig has
959	   * become blocked (no running engines, no runnable engines, some blocked).
960	   */
961	  async function tryCollect(): Promise<CrawlResult | null> {
962	    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
963	    for (const rig of runningRigs) {
964	      for (const engine of rig.engines) {
965	        if (engine.status !== 'running' || !engine.sessionId) continue;
966	
967	        const session = await sessionsBook.get(engine.sessionId);
968	        if (!session || session.status === 'running') continue;
969	
970	        // Terminal session found — collect.
971	        const now = new Date().toISOString();
972	
973	        if (session.status === 'failed' || session.status === 'timeout') {
974	          await failEngine(rig, engine.id, session.error ?? `Session ${session.status}`);
975	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
976	        }
977	
978	        // Completed session — assemble yields via engine's collect() or generic default.
979	        const design = fabricator.getEngineDesign(engine.designId);
980	        let yields: unknown;
981	        if (design?.collect) {
982	          const upstream = buildUpstreamMap(rig);
983	          const givens = resolveYieldRefs({ ...engine.givensSpec }, upstream);
984	          const context = { rigId: rig.id, engineId: engine.id, upstream };
985	          yields = await design.collect(engine.sessionId!, givens, context);
986	        } else {
987	          yields = {
988	            sessionId: session.id,
989	            sessionStatus: session.status,
990	            ...(session.output !== undefined ? { output: session.output } : {}),
991	          };
992	        }
993	
994	        if (!isJsonSerializable(yields)) {
995	          await failEngine(rig, engine.id, 'Session yields are not JSON-serializable');
996	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
997	        }
998	
999	        const updatedEngines = rig.engines.map((e) =>
1000	          e.id === engine.id
1001	            ? { ...e, status: 'completed' as const, yields, completedAt: now }
1002	            : e,
1003	        );
1004	
1005	        const allCompleted = updatedEngines.every((e) => e.status === 'completed');
1006	
1007	        if (allCompleted) {
1008	          await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'completed' });
1009	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'completed' };
1010	        }
1011	
1012	        // Check whether completing this engine has caused the rig to become blocked
1013	        if (isRigBlocked(updatedEngines)) {
1014	          await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'blocked' });
1015	          return { action: 'rig-blocked', rigId: rig.id, writId: rig.writId };
1016	        }
1017	
1018	        await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'running' });
1019	        return { action: 'engine-completed', rigId: rig.id, engineId: engine.id };
1020	      }
1021	    }
1022	    return null;
1023	  }
1024	
1025	  /**
1026	   * Phase 2 — checkBlocked.
1027	   *
1028	   * Query rigs with status 'running' or 'blocked'. For each blocked engine,
1029	   * run the registered checker (respecting pollIntervalMs). If cleared,
1030	   * transition the engine back to pending and restore the rig to running.
1031	   * If not cleared, update lastCheckedAt and continue to the next engine.
1032	   */
1033	  async function tryCheckBlocked(): Promise<CrawlResult | null> {
1034	    // Fetch both running rigs (may have blocked engines) and blocked rigs
1035	    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
1036	    const blockedRigs = await rigsBook.find({ where: [['status', '=', 'blocked']] });
1037	    const rigs = [...runningRigs, ...blockedRigs];
1038	
1039	    for (const rig of rigs) {
1040	      for (const engine of rig.engines) {
1041	        if (engine.status !== 'blocked' || !engine.block) continue;
1042	
1043	        const blockType = blockTypeRegistry.get(engine.block.type);
1044	        if (!blockType) continue; // Type was unregistered after block was created; skip
1045	
1046	        // Poll interval throttle
1047	        if (blockType.pollIntervalMs !== undefined && engine.block.lastCheckedAt) {
1048	          const elapsed = Date.now() - new Date(engine.block.lastCheckedAt).getTime();
1049	          if (elapsed < blockType.pollIntervalMs) continue;
1050	        }
1051	
1052	        let result: CheckResult;
1053	        try {
1054	          result = await blockType.check(engine.block.condition);
1055	        } catch (err) {
1056	          // Log warning, skip — engine stays blocked, retry next cycle
1057	          console.warn(
1058	            `Block checker "${engine.block.type}" threw for engine "${engine.id}" in rig "${rig.id}":`,
1059	            err,
1060	          );
1061	          continue;
1062	        }
1063	
1064	        if (result.status === 'failed') {
1065	          // Permanent failure — fail the engine and rig immediately
1066	          const message = result.reason
1067	            ? `Block "${engine.block.type}" failed: ${result.reason}`
1068	            : `Block "${engine.block.type}" failed permanently`;
1069	          await failEngine(rig, engine.id, message);
1070	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
1071	        }
1072	
1073	        if (result.status !== 'cleared') {
1074	          // Pending (or any unexpected status) — update lastCheckedAt and continue checking other engines
1075	          const now = new Date().toISOString();
1076	          const updatedEngines = rig.engines.map((e) =>
1077	            e.id === engine.id
1078	              ? { ...e, block: { ...e.block!, lastCheckedAt: now } }
1079	              : e,
1080	          );
1081	          await rigsBook.patch(rig.id, { engines: updatedEngines });
1082	          continue; // Check next engine
1083	        }
1084	
1085	        // Cleared — store block record in memory for priorBlock, then transition engine to pending
1086	        const priorBlockRecord = engine.block;
1087	        pendingPriorBlocks.set(`${rig.id}:${engine.id}`, priorBlockRecord);
1088	
1089	        const updatedEngines = rig.engines.map((e) =>
1090	          e.id === engine.id
1091	            ? { ...e, status: 'pending' as const, block: undefined }
1092	            : e,
1093	        );
1094	
1095	        // Restore rig to running if it was blocked; use isRigBlocked on updatedEngines
1096	        // (always false after unblocking, but keeps call sites consistent per R13)
1097	        const stillBlocked = isRigBlocked(updatedEngines);
1098	        const rigStatus = stillBlocked ? 'blocked' : 'running';
1099	
1100	        await rigsBook.patch(rig.id, {
1101	          engines: updatedEngines,
1102	          status: rigStatus,
1103	        });
1104	
1105	        return { action: 'engine-unblocked', rigId: rig.id, engineId: engine.id };
1106	      }
1107	    }
1108	    return null;
1109	  }
1110	
1111	  /**
1112	   * Phase 3 — run.
1113	   *
1114	   * Find the first pending engine in any running rig whose upstream is
1115	   * all completed. Execute it:
1116	   * - Clockwork ('completed') → store yields, mark engine completed,
1117	   *   check for rig completion.
1118	   * - Quick ('launched') → store sessionId, mark engine running.
1119	   * - Blocked ('blocked') → validate block type and condition, persist
1120	   *   block record, check whether rig should enter blocked state.
1121	   */
1122	  async function tryRun(): Promise<CrawlResult | null> {
1123	    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
1124	    for (const rig of runningRigs) {
1125	      const pending = findRunnableEngine(rig);
1126	      if (!pending) continue;
1127	
1128	      const design = fabricator.getEngineDesign(pending.designId);
1129	      if (!design) {
1130	        await failEngine(rig, pending.id, `No engine design found for "${pending.designId}"`);
1131	        return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
1132	      }
1133	
1134	      const now = new Date().toISOString();
1135	      const upstream = buildUpstreamMap(rig);
1136	      const givens = resolveYieldRefs({ ...pending.givensSpec }, upstream);
