      const priorBlockKey = `${rig.id}:${pending.id}`;
      const priorBlock = pendingPriorBlocks.get(priorBlockKey);
      if (priorBlock) pendingPriorBlocks.delete(priorBlockKey);

      const context = {
        rigId: rig.id,
        engineId: pending.id,
        upstream,
        ...(priorBlock ? { priorBlock } : {}),
      };

