  return { action: 'rig-blocked', rigId: rig.id, writId: rig.writId };
}

await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'running' });
return { action: 'engine-completed', rigId: rig.id, engineId: engine.id };
